spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    // Draw horizontal number line
    ctx.strokeStyle = '#374151';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(30, H / 2);
    ctx.lineTo(W - 30, H / 2);
    ctx.stroke();

    // Arrow heads
    ctx.fillStyle = '#374151';
    ctx.beginPath();
    ctx.moveTo(W - 30, H / 2);
    ctx.lineTo(W - 35, H / 2 - 5);
    ctx.lineTo(W - 35, H / 2 + 5);
    ctx.closePath();
    ctx.fill();

    ctx.beginPath();
    ctx.moveTo(30, H / 2);
    ctx.lineTo(35, H / 2 - 5);
    ctx.lineTo(35, H / 2 + 5);
    ctx.closePath();
    ctx.fill();

    // Draw integers from -5 to +5
    var range = 5;
    var spacing = (W - 100) / (2 * range);

    for (var i = -range; i <= range; i++) {
      var x = (W / 2) + (i * spacing);
      var y = H / 2;

      // Highlight animation: pulse on opposite pairs
      var absI = Math.abs(i);
      var pulse = Math.sin(t * 0.08 + absI * 0.3) * 0.5 + 0.5;
      var isActive = (Math.floor(t * 0.02) % (2 * range + 1)) === (i + range);
      var radius = isActive ? 12 + pulse * 4 : 8;

      // Color: negative red, zero gray, positive green
      if (i < 0) ctx.fillStyle = isActive ? '#EF4444' : '#7F1D1D';
      else if (i === 0) ctx.fillStyle = isActive ? '#9CA3AF' : '#4B5563';
      else ctx.fillStyle = isActive ? '#10B981' : '#065F46';

      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.fill();

      // Draw tick mark
      ctx.strokeStyle = '#374151';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(x, y - 15);
      ctx.lineTo(x, y - 20);
      ctx.stroke();

      // Number label
      ctx.font = 'bold 14px -apple-system, sans-serif';
      ctx.fillStyle = '#F3F4F6';
      ctx.textAlign = 'center';
      ctx.fillText(i.toString(), x, y - 30);
    }

    // Draw zero line (vertical axis)
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 2;
    ctx.setLineDash([4, 4]);
    ctx.beginPath();
    ctx.moveTo(W / 2, H / 2 - 40);
    ctx.lineTo(W / 2, H / 2 + 40);
    ctx.stroke();
    ctx.setLineDash([]);

    // Labels
    ctx.font = '12px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';
    ctx.textAlign = 'center';
    ctx.fillText('Negative', W / 4, H / 2 + 50);
    ctx.fillText('Zero', W / 2, H / 2 + 50);
    ctx.fillText('Positive', (3 * W) / 4, H / 2 + 50);
  }
};
